import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import "../../styles/auth.css";

function Login() {
  const navigate  = useNavigate();
  const { login } = useAuth();

  const [email,    setEmail]    = useState("");
  const [password, setPassword] = useState("");
  const [message,  setMessage]  = useState("");
  const [loading,  setLoading]  = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage("");
    const result = await login(email, password);
    setLoading(false);
    if (result.success) {
      if (result.role === "admin")          navigate("/admin/dashboard");
      else if (result.role === "client")    navigate("/client/dashboard");
      else                                  navigate("/freelancer/dashboard");
    } else {
      setMessage(result.message);
    }
  };

  return (
    <div className="register-page">

      {/* ===== LEFT PANEL ===== */}
      <div className="auth-left-panel">
        <h1>Welcome to<br /><span>FreelanceHub</span></h1>
        <p>The professional platform connecting skilled freelancers with clients who need exceptional work.</p>

        <div className="auth-features">
          <div className="auth-feature-item">
            <div className="feature-icon">🚀</div>
            <span>Post projects and find top talent instantly</span>
          </div>
          <div className="auth-feature-item">
            <div className="feature-icon">💼</div>
            <span>Freelancers earn more with direct client connections</span>
          </div>
          <div className="auth-feature-item">
            <div className="feature-icon">🔒</div>
            <span>Secure payments and transparent proposals</span>
          </div>
          <div className="auth-feature-item">
            <div className="feature-icon">⭐</div>
            <span>Rate and review after project completion</span>
          </div>
        </div>
      </div>

      {/* ===== RIGHT PANEL ===== */}
      <div className="auth-right-panel">
        <div className="register-wrapper">

          <div className="register-header">
            <div className="logo-icon">🧳</div>
            <h2>Welcome Back</h2>
            <p>Sign in to your FreelanceHub account</p>
          </div>

          <div className="toggle-container">
            <button className="active">Login</button>
            <button onClick={() => navigate("/register")}>Register</button>
          </div>

          {message && <p className="success-msg">{message}</p>}

          <form onSubmit={handleLogin} className="register-form">
            <label>Email</label>
            <input type="email" placeholder="demo@example.com"
              value={email} onChange={e => setEmail(e.target.value)} required />

            <label>Password</label>
            <input type="password" placeholder="••••••••"
              value={password} onChange={e => setPassword(e.target.value)} required />

            <button type="submit" className="create-btn" disabled={loading}>
              {loading ? "Signing in..." : "Sign In"}
            </button>
          </form>

        </div>
      </div>

    </div>
  );
}

export default Login;
